const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const getPriceForFilters = (p) => (typeof p.min_price === 'number' ? p.min_price : p.base_price);

// Find cart items that are medium bamboo cutting boards under $60 with engraving and quantity 1
const qualifyingCartItems = cartItems
  .map((ci) => {
    const p = products.find((pr) => pr.id === ci.product_id);
    if (!p) return null;
    if (p.category_id !== 'kitchen_cutting_boards') return null;
    if (p.material !== 'bamboo') return null;
    if (p.size_label !== 'Medium (12 x 16 in)') return null;
    const unitPrice = typeof ci.unit_price_snapshot === 'number' ? ci.unit_price_snapshot : p.base_price;
    if (unitPrice > 60) return null;
    if (ci.quantity !== 1) return null;
    if (!ci.engraving_text || String(ci.engraving_text).trim() === '') return null;
    return { cartItem: ci, product: p, unitPrice };
  })
  .filter(Boolean);

// CP1 (0.4): User added a qualifying medium bamboo cutting board with engraving and quantity 1 under $60
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.4 });

// Determine the cheapest qualifying medium bamboo cutting board in the catalog
const qualifyingProducts = products.filter((p) =>
  p.category_id === 'kitchen_cutting_boards' &&
  p.material === 'bamboo' &&
  p.size_label === 'Medium (12 x 16 in)' &&
  getPriceForFilters(p) <= 60
);

let cheapestPrice = null;
if (qualifyingProducts.length > 0) {
  qualifyingProducts.forEach((p) => {
    const price = getPriceForFilters(p);
    if (cheapestPrice === null || price < cheapestPrice) cheapestPrice = price;
  });
}

let choseCheapest = false;
if (cheapestPrice !== null && qualifyingCartItems.length > 0) {
  choseCheapest = qualifyingCartItems.some((item) => Math.abs(item.unitPrice - cheapestPrice) < 0.01);
}

// CP2 (0.6): The added cutting board is the cheapest qualifying option
checkpoints.push({ passed: choseCheapest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const shippingOptions = JSON.parse(localStorage.getItem('shipping_options') || '[]');

const getPriceForFilters = (p) => (typeof p.min_price === 'number' ? p.min_price : p.base_price);

// Find a cart item that matches the 4x stainless steel 20 oz tumbler criteria
let tumblerItem = null;
for (const ci of cartItems) {
  const p = products.find((pr) => pr.id === ci.product_id);
  if (!p) continue;
  if (p.category_id !== 'drinkware_tumblers') continue;
  if (p.material !== 'stainless_steel') continue;
  if (typeof p.capacity_oz !== 'number' || p.capacity_oz !== 20) continue;
  const unitPrice = typeof ci.unit_price_snapshot === 'number' ? ci.unit_price_snapshot : p.base_price;
  if (unitPrice > 35) continue;
  if ((p.rating_average || 0) < 4.0) continue;
  if (ci.quantity !== 4) continue;
  if (!ci.engraving_text || String(ci.engraving_text).trim() === '') continue;
  if (ci.fulfillment_type !== 'shipping') continue;
  if (!ci.shipping_option_id) continue;
  tumblerItem = { cartItem: ci, product: p, unitPrice };
  break;
}

// CP1 (0.4): User added 4 qualifying stainless 20 oz tumblers with engraving and shipping
checkpoints.push({ passed: !!tumblerItem, weight: 0.4 });

// CP2 (0.3): The selected tumbler is the cheapest qualifying stainless 20 oz tumbler under $35 with rating ≥4
let isCheapestProduct = false;
if (tumblerItem) {
  const qualifyingProducts = products.filter((p) =>
    p.category_id === 'drinkware_tumblers' &&
    p.material === 'stainless_steel' &&
    typeof p.capacity_oz === 'number' && p.capacity_oz === 20 &&
    getPriceForFilters(p) <= 35 &&
    (p.rating_average || 0) >= 4.0
  );
  if (qualifyingProducts.length > 0) {
    let cheapestPrice = null;
    qualifyingProducts.forEach((p) => {
      const price = getPriceForFilters(p);
      if (cheapestPrice === null || price < cheapestPrice) cheapestPrice = price;
    });
    if (cheapestPrice !== null) {
      isCheapestProduct = Math.abs(tumblerItem.unitPrice - cheapestPrice) < 0.01;
    }
  }
}
checkpoints.push({ passed: isCheapestProduct, weight: 0.3 });

// CP3 (0.3): Selected shipping option is the cheapest one for this product that delivers within 10 business days
let hasBestShipping = false;
if (tumblerItem) {
  const optionsForProduct = shippingOptions.filter((o) =>
    o.product_id === tumblerItem.product.id &&
    !o.is_pickup_option &&
    typeof o.delivery_max_business_days === 'number' &&
    o.delivery_max_business_days <= 10
  );
  if (optionsForProduct.length > 0) {
    let minShipPrice = null;
    optionsForProduct.forEach((o) => {
      if (minShipPrice === null || o.price < minShipPrice) minShipPrice = o.price;
    });
    const selectedOpt = optionsForProduct.find((o) => o.id === tumblerItem.cartItem.shipping_option_id);
    if (selectedOpt && minShipPrice !== null) {
      hasBestShipping = Math.abs(selectedOpt.price - minShipPrice) < 0.01;
    }
  }
}
checkpoints.push({ passed: hasBestShipping, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

let searchParams = null;
try {
  const raw = localStorage.getItem('task3_searchParams');
  searchParams = raw ? JSON.parse(raw) : null;
} catch (e) {
  searchParams = null;
}

let comparedIds = [];
try {
  const rawIds = localStorage.getItem('task3_comparedProductIds');
  comparedIds = rawIds ? JSON.parse(rawIds) : [];
} catch (e) {
  comparedIds = [];
}

const getPriceForFilters = (p) => (typeof p.min_price === 'number' ? p.min_price : p.base_price);

// CP1 (0.3): User searched/filtered for phone stands under $40 in a relevant way
let usedCorrectSearch = false;
if (searchParams && typeof searchParams === 'object') {
  const filters = searchParams.filters || {};
  const query = String(searchParams.query || '').toLowerCase();
  const hasMaxPrice = typeof filters.max_price === 'number' && filters.max_price <= 40;
  const targetsPhoneStands = (filters.category_id === 'phone_stands') || query.includes('phone');
  usedCorrectSearch = hasMaxPrice && targetsPhoneStands;
}
checkpoints.push({ passed: usedCorrectSearch, weight: 0.3 });

// Build sets of compared walnut and maple phone stands under $40 with engraving
const comparedWalnut = [];
const comparedMaple = [];

products.forEach((p) => {
  if (p.category_id !== 'phone_stands') return;
  if (!p.material || (p.material !== 'walnut' && p.material !== 'maple')) return;
  const price = getPriceForFilters(p);
  if (price > 40) return;
  if (!p.has_engraving_text) return;
  if (!Array.isArray(comparedIds) || comparedIds.indexOf(p.id) === -1) return;
  if (p.material === 'walnut') comparedWalnut.push(p);
  if (p.material === 'maple') comparedMaple.push(p);
});

const comparedBothMaterials = comparedWalnut.length > 0 && comparedMaple.length > 0;
// CP2 (0.3): User actually compared at least one walnut and one maple candidate under $40
checkpoints.push({ passed: comparedBothMaterials, weight: 0.3 });

// CP3 (0.4): User added the higher-rated of the best walnut vs best maple candidate to cart with engraving
let addedHigherRated = false;
if (comparedBothMaterials) {
  const bestWalnut = comparedWalnut.slice().sort((a, b) => (b.rating_average || 0) - (a.rating_average || 0))[0];
  const bestMaple = comparedMaple.slice().sort((a, b) => (b.rating_average || 0) - (a.rating_average || 0))[0];
  if (bestWalnut && bestMaple) {
    const walnutRating = bestWalnut.rating_average || 0;
    const mapleRating = bestMaple.rating_average || 0;
    let expectedIds = [];
    if (walnutRating > mapleRating) {
      expectedIds = [bestWalnut.id];
    } else if (mapleRating > walnutRating) {
      expectedIds = [bestMaple.id];
    } else {
      // Tie: either of the top walnut or maple options is acceptable
      expectedIds = [bestWalnut.id, bestMaple.id];
    }

    addedHigherRated = cartItems.some((ci) => {
      if (expectedIds.indexOf(ci.product_id) === -1) return false;
      if (ci.quantity !== 1) return false;
      if (!ci.engraving_text || String(ci.engraving_text).trim() === '') return false;
      const prod = products.find((p) => p.id === ci.product_id);
      const unitPrice = typeof ci.unit_price_snapshot === 'number' ? ci.unit_price_snapshot : (prod ? prod.base_price : 0);
      return unitPrice <= 40;
    });
  }
}
checkpoints.push({ passed: addedHigherRated, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const requests = JSON.parse(localStorage.getItem('bulk_quote_requests') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

// Find the most recent bulk quote request that matches product material/category and quantity/budget
const candidateRequests = requests.filter((req) => {
  const p = products.find((pr) => pr.id === req.product_id);
  if (!p) return false;
  if (p.category_id !== 'keychains_accessories') return false;
  if (p.material !== 'aluminum') return false;
  if (!p.is_bulk_order_available) return false;
  if (req.quantity_requested !== 50) return false;
  if (typeof req.budget_amount !== 'number') return false;
  if (req.budget_amount !== 300) return false; // exact $300 budget
  return true;
});

let request = null;
if (candidateRequests.length > 0) {
  candidateRequests.sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0));
  request = candidateRequests[0];
}

// CP1 (0.5): User submitted a bulk quote for 50 aluminum keychains with $300 budget
checkpoints.push({ passed: !!request, weight: 0.5 });

// CP2 (0.25): Timeline is set to the ~30-day option
let correctTimeline = false;
if (request) {
  correctTimeline = request.timeline_option === 'need_in_30_days';
}
checkpoints.push({ passed: correctTimeline, weight: 0.25 });

// CP3 (0.25): Project details mention engraved keychains and include a company name
let goodDetails = false;
if (request) {
  const details = String(request.project_details || '').toLowerCase();
  const mentionsKeychain = details.includes('keychain');
  const mentionsEngrave = details.includes('engraved') || details.includes('engraving') || details.includes('engrave');
  const hasCompany = !!request.company_name && String(request.company_name).trim() !== '';
  goodDetails = mentionsKeychain && mentionsEngrave && hasCompany;
}
checkpoints.push({ passed: goodDetails, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Find a wishlist item that matches a rustic 12 x 18 in wedding welcome sign with dark walnut finish and personalization
let savedItem = null;
for (const wi of wishlistItems) {
  const p = products.find((pr) => pr.id === wi.product_id);
  if (!p) continue;
  if (p.category_id !== 'weddings') continue;
  if (p.product_type !== 'welcome_sign_plaque') continue;
  if (p.size_label !== '12 x 18 in') continue;
  if (p.style_theme !== 'rustic') continue;
  if (wi.wood_finish_selection !== 'dark_walnut') continue;
  if (!wi.engraving_text || String(wi.engraving_text).trim() === '') continue;
  if (!wi.event_date_text || String(wi.event_date_text).trim() === '') continue;
  savedItem = { wi, product: p };
  break;
}

// CP1 (0.5): User saved a correctly configured rustic 12 x 18 in wedding welcome sign to the wishlist
checkpoints.push({ passed: !!savedItem, weight: 0.5 });

// CP2 (0.25): The chosen sign is among the most popular rustic 12 x 18 in wedding welcome signs (top 2 by popularity)
let isPopularChoice = false;
if (savedItem) {
  const matchingProducts = products.filter((p) =>
    p.category_id === 'weddings' &&
    p.product_type === 'welcome_sign_plaque' &&
    p.size_label === '12 x 18 in' &&
    p.style_theme === 'rustic'
  );
  if (matchingProducts.length > 0) {
    matchingProducts.sort((a, b) => (b.popularity_score || 0) - (a.popularity_score || 0));
    const idx = matchingProducts.findIndex((p) => p.id === savedItem.product.id);
    isPopularChoice = idx > -1 && idx <= 1; // within top 2
  }
}
checkpoints.push({ passed: isPopularChoice, weight: 0.25 });

// CP3 (0.25): The same product was not added to the cart (saved to wishlist instead of cart)
let notInCart = false;
if (savedItem) {
  notInCart = !cartItems.some((ci) => ci.product_id === savedItem.product.id);
}
checkpoints.push({ passed: notInCart, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const getPriceForFilters = (p) => (typeof p.min_price === 'number' ? p.min_price : p.base_price);

// Identify cart items that correctly satisfy all anniversary + price + rating + free wrap + engraving requirements
const qualifyingCartItems = cartItems.filter((ci) => {
  const p = products.find((pr) => pr.id === ci.product_id);
  if (!p) return false;
  if (!Array.isArray(p.occasions) || p.occasions.indexOf('anniversary') === -1) return false;
  const price = getPriceForFilters(p);
  if (price > 40) return false;
  if ((p.rating_average || 0) < 4.0) return false;
  if (!p.has_engraving_text) return false;
  if (!p.supports_gift_wrap || !p.has_free_gift_wrap) return false;
  if (ci.quantity !== 1) return false;
  if (!ci.engraving_text || String(ci.engraving_text).trim() === '') return false;
  if (ci.gift_wrap_selection !== 'free_gift_wrap') return false;
  return true;
});

// Also detect anniversary gifts in cart that meet price/rating but do NOT meet the free gift-wrap condition
const disqualifyingAnniversaryItems = cartItems.filter((ci) => {
  const p = products.find((pr) => pr.id === ci.product_id);
  if (!p) return false;
  if (!Array.isArray(p.occasions) || p.occasions.indexOf('anniversary') === -1) return false;
  const price = getPriceForFilters(p);
  if (price > 40) return false;
  if ((p.rating_average || 0) < 4.0) return false;
  // Disqualifying if not both product has free wrap and the cart item selected it
  const hasFree = !!p.has_free_gift_wrap;
  const usesFreeWrap = ci.gift_wrap_selection === 'free_gift_wrap';
  return !(hasFree && usesFreeWrap);
});

// CP1 (0.6): At least one correctly configured anniversary gift with free gift wrap and engraving was added (quantity 1)
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.6 });

// CP2 (0.4): User did not also keep a wrong anniversary gift in the cart that lacks free gift wrap
checkpoints.push({ passed: qualifyingCartItems.length > 0 && disqualifyingAnniversaryItems.length === 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const contexts = JSON.parse(localStorage.getItem('store_pickup_contexts') || '[]');
const stores = JSON.parse(localStorage.getItem('store_locations') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const getPriceForFilters = (p) => (typeof p.min_price === 'number' ? p.min_price : p.base_price);

const ctx = contexts.find((c) => c.id === 'current') || null;
const selectedStore = ctx ? stores.find((s) => s.id === ctx.selected_store_location_id) : null;

// CP1 (0.3): User selected a store near ZIP 94103 that supports same-day pickup
let pickupContextOk = false;
if (ctx && selectedStore) {
  const zip = String(ctx.selected_zip || '').trim();
  const storeZip = String(selectedStore.postal_code || '').trim();
  pickupContextOk = zip.startsWith('94103') && storeZip.startsWith('94103') && !!selectedStore.supports_same_day_pickup;
}
checkpoints.push({ passed: pickupContextOk, weight: 0.3 });

// Helper: detect qualifying pen products for same-day pickup
const isQualifyingPenProduct = (p) => {
  if (!p) return false;
  if (p.category_id !== 'pens_office') return false;
  if (!p.has_engraving_text) return false;
  if (!p.is_store_pickup_eligible || !p.is_same_day_pickup_eligible) return false;
  const price = getPriceForFilters(p);
  if (price > 25) return false;
  if ((p.rating_average || 0) < 4.0) return false;
  return true;
};

// Find cart items that are correctly configured 3-pen same-day pickup orders at the selected store
const qualifyingCartItems = cartItems.filter((ci) => {
  const p = products.find((pr) => pr.id === ci.product_id);
  if (!isQualifyingPenProduct(p)) return false;
  if (ci.fulfillment_type !== 'store_pickup') return false;
  if (!selectedStore || ci.store_location_id !== selectedStore.id) return false;
  if (ci.quantity !== 3) return false;
  if (!Array.isArray(ci.engraving_names) || ci.engraving_names.length !== 3) return false;
  const trimmedNames = ci.engraving_names.map((n) => String(n || '').trim()).filter((n) => n);
  if (trimmedNames.length !== 3) return false;
  const uniqueNames = Array.from(new Set(trimmedNames));
  if (uniqueNames.length !== 3) return false; // three different names
  if (ci.ink_color_selection !== 'black') return false;
  return true;
});

// CP2 (0.5): User added 3 qualifying engraved pens with three different names and black ink for same-day store pickup at the selected store
checkpoints.push({ passed: qualifyingCartItems.length > 0, weight: 0.5 });

// Identify any misconfigured cart items for qualifying pen products (wrong fulfillment, quantity, names, or ink color)
const misconfiguredPenItems = cartItems.filter((ci) => {
  const p = products.find((pr) => pr.id === ci.product_id);
  if (!isQualifyingPenProduct(p)) return false;
  // Treat as misconfigured unless it matches the expected configuration
  if (!selectedStore) return true;
  if (ci.fulfillment_type !== 'store_pickup') return true;
  if (ci.store_location_id !== selectedStore.id) return true;
  if (ci.quantity !== 3) return true;
  if (!Array.isArray(ci.engraving_names) || ci.engraving_names.length !== 3) return true;
  const trimmedNames = ci.engraving_names.map((n) => String(n || '').trim()).filter((n) => n);
  if (trimmedNames.length !== 3) return true;
  const uniqueNames = Array.from(new Set(trimmedNames));
  if (uniqueNames.length !== 3) return true;
  if (ci.ink_color_selection !== 'black') return true;
  return false;
});

// CP3 (0.2): No misconfigured cart items exist for qualifying same-day pen products
checkpoints.push({ passed: qualifyingCartItems.length > 0 && misconfiguredPenItems.length === 0, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const appointments = JSON.parse(localStorage.getItem('consultation_appointments') || '[]');

// Find the most recent relevant consultation appointment for wall art & large signs via video call
const candidateAppts = appointments.filter((a) =>
  a.project_type === 'wall_art_large_signs' &&
  a.consultation_format === 'video_call' &&
  (a.status === 'requested' || a.status === 'scheduled')
);

let appt = null;
if (candidateAppts.length > 0) {
  candidateAppts.sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0));
  appt = candidateAppts[0];
}

// CP1 (0.6): Appointment has ~$400 budget, 36 x 24 mention, wall art/sign description, and contact details
let hasCorrectConsult = false;
if (appt) {
  const desc = String(appt.project_description || '').toLowerCase();
  const mentionsSize = desc.includes('36 x 24') || desc.includes('36x24');
  const mentionsWallArt = desc.includes('wall') && (desc.includes('art') || desc.includes('sign'));
  const mentionsBudgetText = desc.includes('400') || desc.includes('$400');
  const hasBudgetAmount = typeof appt.estimated_budget_amount === 'number' && Math.abs(appt.estimated_budget_amount - 400) < 0.01;
  const hasContact = !!appt.contact_name && String(appt.contact_name).trim() !== '' &&
                     !!appt.contact_email && String(appt.contact_email).trim() !== '';
  hasCorrectConsult = mentionsSize && mentionsWallArt && hasBudgetAmount && hasContact;
}
checkpoints.push({ passed: hasCorrectConsult, weight: 0.6 });

// CP2 (0.4): Appointment is scheduled for a specific future date/time relative to 2026-03-03T09:00:00Z
let hasFutureTime = false;
if (appt && appt.appointment_start) {
  const start = new Date(appt.appointment_start);
  const baseline = new Date('2026-03-03T09:00:00Z');
  if (!isNaN(start.getTime()) && !isNaN(baseline.getTime())) {
    hasFutureTime = start > baseline;
  }
}
checkpoints.push({ passed: hasFutureTime, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
